644	     * @returns {Promise<RawImage>} The resized image.
645	     */
646	    async thumbnail(image, size, resample = 2) {
647	        const input_height = image.height;
648	        const input_width = image.width;
649	
650	        const output_height = size.height;
651	        const output_width = size.width;
652	
653	        // We always resize to the smallest of either the input or output size.
654	        let height = Math.min(input_height, output_height)
655	        let width = Math.min(input_width, output_width)
