5	export async function loadAudio(url) {
6	  // NOTE: Since the Web Audio API is not available in Node.js, we will need to use the `wavefile` library to obtain the raw audio data.
7	  // For more information, see: https://huggingface.co/docs/transformers.js/guides/node-audio-processing
8	  let wavefile = (await import("wavefile")).default;
9	
10	  // Load audio data
11	  let buffer = Buffer.from(await fetch(url).then((x) => x.arrayBuffer()));
12	
13	  // Read .wav file and convert it to required format
14	  let wav = new wavefile.WaveFile(buffer);
15	  wav.toBitDepth("32f"); // Pipeline expects input as a Float32Array
16	  wav.toSampleRate(16000); // Whisper expects audio with a sampling rate of 16000
17	  let audioData = wav.getSamples();
18	  if (Array.isArray(audioData)) {
19	    if (audioData.length > 1) {
20	      const SCALING_FACTOR = Math.sqrt(2);
21	
22	      // Merge channels (into first channel to save memory)
23	      for (let i = 0; i < audioData[0].length; ++i) {
24	        audioData[0][i] = (SCALING_FACTOR * (audioData[0][i] + audioData[1][i])) / 2;
25	      }
26	    }
27	
28	    // Select first channel
29	    audioData = audioData[0];
30	  }
31	  return audioData;
32	}
33	/**
34	 * Deep equality test (for arrays and objects) with tolerance for floating point numbers
35	 * @param {any} val1 The first item
36	 * @param {any} val2 The second item
37	 * @param {number} tol Tolerance for floating point numbers
38	 */
39	export function compare(val1, val2, tol = 0.1) {
40	  if (val1 !== null && val2 !== null && typeof val1 === "object" && typeof val2 === "object") {
41	    // Both are non-null objects
42	
43	    if (Array.isArray(val1) && Array.isArray(val2)) {
44	      expect(val1).toHaveLength(val2.length);
45	
46	      for (let i = 0; i < val1.length; ++i) {
47	        compare(val1[i], val2[i], tol);
48	      }
49	    } else {
50	      expect(Object.keys(val1)).toHaveLength(Object.keys(val2).length);
51	
52	      for (let key in val1) {
53	        compare(val1[key], val2[key], tol);
54	      }
55	    }
56	  } else {
57	    // At least one of them is not an object
58	    // First check that both have the same type
59	    expect(typeof val1).toEqual(typeof val2);
60	
61	    if (typeof val1 === "number" && (!Number.isInteger(val1) || !Number.isInteger(val2))) {
62	      // If both are numbers and at least one of them is not an integer
63	      expect(val1).toBeCloseTo(val2, -Math.log10(tol));
64	    } else {
65	      // Perform equality test
66	      expect(val1).toEqual(val2);
67	    }
68	  }
69	}
