export class RawImage {
    constructor(data, width, height, channels) {
        this.data = data;        // Uint8ClampedArray | Uint8Array
        this.width = width;
        this.height = height;
        this.channels = channels;  // 1, 2, 3, or 4
    }

    get size() {
        return [this.width, this.height];
    }

    static async read(input) {
        // Accepts: RawImage, string, URL, Blob, HTMLCanvasElement, OffscreenCanvas
        if (input instanceof RawImage) return input;
        else if (typeof input === 'string' || input instanceof URL) return this.fromURL(input);
        else if (input instanceof Blob) return this.fromBlob(input);
        else if (input instanceof HTMLCanvasElement || input instanceof OffscreenCanvas) return this.fromCanvas(input);
    }

    static fromCanvas(canvas) {
        const ctx = canvas.getContext('2d');
        const data = ctx.getImageData(0, 0, canvas.width, canvas.height).data;
        return new RawImage(data, canvas.width, canvas.height, 4);
    }

    static async fromURL(url) {
        const response = await getFile(url);
        const blob = await response.blob();
        return this.fromBlob(blob);
    }

    static async fromBlob(blob) {
        if (IS_BROWSER_OR_WEBWORKER) {
            const img = await loadImageFunction(blob);
            const ctx = createCanvasFunction(img.width, img.height).getContext('2d');
            ctx.drawImage(img, 0, 0);
            return new this(ctx.getImageData(0, 0, img.width, img.height).data, img.width, img.height, 4);
        } else {
            const img = sharp(await blob.arrayBuffer());
            return await loadImageFunction(img);
        }
    }

    static fromTensor(tensor, channel_format = 'CHW') { /* ... */ }
}
